// game-of-life.ts
export type Cell = [number, number];

export const nextGeneration = (liveCells: Cell[]): Cell[] =>
  candidates(liveCells).filter(
    (cell) => countLiveNeighbors(cell, liveCells) === 3
  );

const candidates = (liveCells: Cell[]): Cell[] =>
  liveCells.flatMap((cell) => [cell, ...neighborsOf(cell)]);

const neighborsOf = ([x, y]: Cell): Cell[] =>
  [-1, 0, 1].flatMap((dx) =>
    [-1, 0, 1]
      .filter((dy) => !(dx === 0 && dy === 0))
      .map((dy): Cell => [x + dx, y + dy])
  );

const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
  liveCells.filter((other) => isNeighbor(cell, other)).length;

const isNeighbor = ([ax, ay]: Cell, [bx, by]: Cell): boolean =>
  Math.abs(ax - bx) <= 1 &&
  Math.abs(ay - by) <= 1 &&
  !(ax === bx && ay === by);

